def clip(p):
    return max(0.0, min(1.0, p))
print(clip(1.5), clip(-0.2))
print('ok', True)
print('range', '[0,1]')

def d(p, low=0.3, high=0.7):
    if p >= high:
        return 'queue'
    if p <= low:
        return 'skip'
    return 'abstain'
print(d(0.5))
print('low', 0.3)
print('high', 0.7)
